   195	export function buildCustomEndpoint(baseUrl: string): ProviderEndpoint {
   196	  // Strip trailing /v1 (or /v1/) since openaiPath already includes /v1
   197	  const normalized = normalizeProviderBaseUrl(baseUrl);
   198	  return {
