   206	export function buildEndpointOverride(baseUrl: string, templateKey: string): ProviderEndpoint {
   207	  const template = PROVIDER_ENDPOINTS[templateKey];
   208	  if (!template) {
   209	    throw new Error(`No provider endpoint template configured for: ${templateKey}`);
   210	  }
   211	  return {
   212	    ...template,
   213	    baseUrl: normalizeProviderBaseUrl(baseUrl),
   214	  };
   215	}
