import { ProviderClient } from '/workspace/manifest/packages/backend/src/routing/proxy/provider-client';

async function main() {
  const seenModels: string[] = [];
  const originalFetch = globalThis.fetch;
  globalThis.fetch = (async (_url: RequestInfo | URL, init?: RequestInit) => {
    const payload = JSON.parse(String(init?.body ?? '{}')) as { model?: string };
    seenModels.push(payload.model ?? '');
    return new Response('{"id":"ok","choices":[]}', {
      status: 200,
      headers: { 'content-type': 'application/json' },
    });
  }) as typeof fetch;

  try {
    const providerClient = new ProviderClient();
    const customProviderRepo = {
      findOne: async ({ where }: { where: { id: string } }) => ({
        id: where.id,
        base_url: 'https://api.fireworks.ai/inference/v1',
      }),
    };
    const service = new ProxyFallbackService(
      {} as never,
      customProviderRepo as never,
      {} as never,
      {} as never,
      providerClient,
      {} as never,
      {} as never,
    );

    await service.tryForwardToProvider({
      provider: 'custom:cp-fireworks',
      apiKey: 'sk-test',
      model: 'custom:cp-fireworks/accounts/fireworks/routers/kimi-k2p5-turbo',
      body: { messages: [{ role: 'user', content: 'hello' }] },
      stream: false,
      sessionKey: 'session-1',
    });

    assert.equal(
      seenModels[0],
      'accounts/fireworks/routers/kimi-k2p5-turbo',
      `expected raw upstream model, got ${seenModels[0]}`,
    );
    console.log('PASS custom provider forwards raw Fireworks model:', seenModels[0]);
  } finally {
    globalThis.fetch = originalFetch;
  }
}

main().catch((error) => {
  console.error(error);
  process.exit(1);
});
