  /** Unique model name for model lookups. */
  static modelKey(id: string, modelName: string): string {
    return `custom:${id}/${modelName}`;
  }

  /** Strip the synthesized custom provider prefix for upstream API calls. */
  static rawModelName(modelName: string, providerKey?: string): string {
    if (providerKey) {
      const prefix = `${providerKey}/`;
      return modelName.startsWith(prefix) ? modelName.substring(prefix.length) : modelName;
